import java.util.Scanner;

public class SecureBufferHandling {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Ensure that the buffer size is at least equal to the length of user input
        char[] buffer = new char[name.length()];

        // Copying user input into the buffer with proper bounds checking
        if (name.length() <= buffer.length) {
            name.getChars(0, name.length(), buffer, 0);
            System.out.println("Hello, " + new String(buffer));
        } else {
            System.out.println("Input exceeds buffer capacity. Please enter a shorter name.");
        }
    }
}

